import { Sudoku } from './sudoku';

export class Game {
  constructor() {
    this.sudoku = new Sudoku(); 
    this.history = [];
    this.redoStack = []; // 专门存重做的数据
    this.isPaused = false;
  }

  getSudoku() {
    return this.sudoku;
  }

  guess(row, col, value) {
    if (this.isPaused) return;
    this.makeMove(row, col, value);
  }

  makeMove(row, col, value) {
    this.history.push(this.sudoku.clone());
    this.redoStack = []; // 有新动作时，重做栈要清空
    this.sudoku.guess(row, col, value);
  }

  // 契约测试要求的 Undo/Redo 相关方法
  undo() {
    if (this.canUndo()) {
      this.redoStack.push(this.sudoku.clone());
      this.sudoku = this.history.pop();
    }
  }

  redo() {
    if (this.canRedo()) {
      this.history.push(this.sudoku.clone());
      this.sudoku = this.redoStack.pop();
    }
  }

  canUndo() {
    return this.history.length > 0;
  }

  canRedo() {
    return this.redoStack.length > 0;
  }

  toJSON() {
    return {
      sudoku: this.sudoku.toJSON(),
      history: this.history.map(s => s.toJSON()),
      redoStack: this.redoStack.map(s => s.toJSON())
    };
  }

  startNew(diff) {
    this.sudoku = Sudoku.generate(diff);
    this.history = [];
    this.redoStack = [];
    this.isPaused = false;
  }

  pause() { this.isPaused = true; }
  resume() { this.isPaused = false; }
}

export const gameInstance = new Game();
export default gameInstance;
